import { ChangeDetectionStrategy, Component, computed, inject, output, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { CryptoService } from '../../services/crypto.service';
import { Cryptocurrency } from '../../models/crypto.model';
import { ChartComponent } from '../chart/chart.component';

type TradeType = 'BUY' | 'SELL';
interface Order {
  id: number;
  coin: Cryptocurrency;
  type: TradeType;
  amount: number;
  price: number;
  status: 'OPEN' | 'FILLED';
}

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CommonModule, FormsModule, ChartComponent]
})
export class DashboardComponent {
  logout = output<void>();

  cryptoService = inject(CryptoService);
  allCoins = this.cryptoService.cryptoData;

  selectedCoin = signal<Cryptocurrency>(this.allCoins()[0]);
  isTradingActive = signal(true);

  tradeType = signal<TradeType>('BUY');
  tradeAmount = signal(0);
  limitPrice = signal(0);
  orders = signal<Order[]>([]);

  portfolio = signal<{ [key: string]: number }>({
    'usd': 10000,
    'btc': 0,
    'eth': 0,
    'sol': 0
  });

  usdBalance = computed(() => this.portfolio()['usd']);
  assetBalance = computed(() => {
    const coinSymbol = this.selectedCoin().symbol.toLowerCase();
    return this.portfolio()[coinSymbol] || 0;
  });

  totalCost = computed(() => this.tradeAmount() * this.selectedCoin().current_price);

  selectCoin(coin: Cryptocurrency) {
    this.selectedCoin.set(coin);
  }

  toggleTrading() {
    this.isTradingActive.update(active => !active);
  }

  setTradeType(type: TradeType) {
    this.tradeType.set(type);
  }

  placeOrder() {
    if (!this.tradeAmount() || this.tradeAmount() <= 0) {
      alert('Please enter a valid amount.');
      return;
    }
    const coin = this.selectedCoin();
    const amount = this.tradeAmount();
    const type = this.tradeType();

    // Simulate immediate market order
    this.portfolio.update(p => {
      const newPortfolio = {...p};
      const coinSymbol = coin.symbol.toLowerCase();
      const cost = amount * coin.current_price;

      if (type === 'BUY') {
        if (newPortfolio['usd'] < cost) {
          alert('Insufficient USD balance.');
          return p;
        }
        newPortfolio['usd'] -= cost;
        newPortfolio[coinSymbol] = (newPortfolio[coinSymbol] || 0) + amount;
      } else { // SELL
        if ((newPortfolio[coinSymbol] || 0) < amount) {
          alert(`Insufficient ${coin.symbol} balance.`);
          return p;
        }
        newPortfolio['usd'] += cost;
        newPortfolio[coinSymbol] -= amount;
      }
      return newPortfolio;
    });

    // Add to order history
    const newOrder: Order = {
      id: Date.now(),
      coin: coin,
      type: type,
      amount: amount,
      price: coin.current_price,
      status: 'FILLED'
    };
    this.orders.update(o => [newOrder, ...o].slice(0, 10)); // Keep last 10 orders

    // Reset form
    this.tradeAmount.set(0);
  }

  formatCurrency(value: number): string {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 2, maximumFractionDigits: value < 1 ? 6 : 2 }).format(value);
  }

  formatNumber(value: number | undefined): string {
      if (value === undefined) return '0.0000';
      return value.toFixed(4);
  }
}

import { ChangeDetectionStrategy, Component, computed, input } from '@angular/core';

@Component({
  selector: 'app-chart',
  templateUrl: './chart.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class ChartComponent {
  data = input.required<number[]>();
  isPositiveChange = input(true);

  viewBox = '0 0 300 100';

  chartColor = computed(() => this.isPositiveChange() ? '#4ade80' : '#f87171'); // green-400 or red-400

  pathData = computed(() => {
    const dataPoints = this.data();
    if (dataPoints.length < 2) return '';

    const max = Math.max(...dataPoints);
    const min = Math.min(...dataPoints);
    const range = max - min === 0 ? 1 : max - min;

    const points = dataPoints.map((d, i) => {
      const x = (i / (dataPoints.length - 1)) * 300;
      const y = 100 - ((d - min) / range) * 90 - 5; // 5 padding top/bottom
      return `${x},${y}`;
    });

    return `M ${points.join(' L ')}`;
  });

  areaPathData = computed(() => {
    const path = this.pathData();
    if (!path) return '';
    return `${path} L 300,100 L 0,100 Z`;
  });
}

import { ChangeDetectionStrategy, Component, computed, effect, inject, output, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { CryptoService } from '../../services/crypto.service';
import { Cryptocurrency } from '../../models/crypto.model';
import { ChartComponent } from '../chart/chart.component';

type TradeType = 'BUY' | 'SELL';
interface Order {
  id: number;
  coin: Cryptocurrency;
  type: TradeType;
  amount: number;
  price: number;
  status: 'OPEN' | 'FILLED';
}

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CommonModule, FormsModule, ChartComponent]
})
export class DashboardComponent {
  logout = output<void>();

  cryptoService = inject(CryptoService);
  allCoins = this.cryptoService.cryptoData;

  selectedCoin = signal<Cryptocurrency>(this.allCoins()[0]);
  isTradingActive = signal(true);

  tradeType = signal<TradeType>('BUY');
  orderType = signal<'MARKET' | 'LIMIT'>('MARKET');
  tradeAmount = signal(0);
  limitPrice = signal(0);
  orders = signal<Order[]>([]);

  portfolio = signal<{ [key: string]: number }>({
    'usd': 10000,
    'btc': 0,
    'eth': 0,
    'sol': 0,
    'doge': 0
  });

  constructor() {
    effect(() => {
        // Rerun when prices change to check if limit orders can be filled
        const coins = this.allCoins();
        if (this.orders().some(o => o.status === 'OPEN')) {
            const currentPrices = new Map(coins.map(c => [c.id, c.current_price]));
            this.processOpenOrders(currentPrices);
        }
    });
  }

  usdBalance = computed(() => this.portfolio()['usd']);
  assetBalance = computed(() => {
    const coinSymbol = this.selectedCoin().symbol.toLowerCase();
    return this.portfolio()[coinSymbol] || 0;
  });

  totalCost = computed(() => {
    const amount = this.tradeAmount();
    if (this.orderType() === 'LIMIT') {
        return amount * (this.limitPrice() || 0);
    }
    return amount * this.selectedCoin().current_price;
  });

  selectCoin(coin: Cryptocurrency) {
    this.selectedCoin.set(coin);
  }

  toggleTrading() {
    this.isTradingActive.update(active => !active);
  }

  setTradeType(type: TradeType) {
    this.tradeType.set(type);
  }

  setOrderType(type: 'MARKET' | 'LIMIT') {
    this.orderType.set(type);
  }

  placeOrder() {
    if (!this.tradeAmount() || this.tradeAmount() <= 0) {
      alert('Please enter a valid amount.');
      return;
    }

    if (this.orderType() === 'LIMIT' && (!this.limitPrice() || this.limitPrice() <= 0)) {
        alert('Please enter a valid limit price.');
        return;
    }

    const coin = this.selectedCoin();
    const amount = this.tradeAmount();
    const type = this.tradeType();

    if (this.orderType() === 'MARKET') {
        this.executeMarketOrder(coin, amount, type);
    } else {
        this.createLimitOrder(coin, amount, type, this.limitPrice());
    }

    this.tradeAmount.set(0);
    this.limitPrice.set(0);
  }

  private executeMarketOrder(coin: Cryptocurrency, amount: number, type: TradeType) {
    const cost = amount * coin.current_price;
    let orderPlaced = false;

    this.portfolio.update(p => {
      const newPortfolio = {...p};
      const coinSymbol = coin.symbol.toLowerCase();

      if (type === 'BUY') {
        if (newPortfolio['usd'] < cost) {
          alert('Insufficient USD balance.');
          return p;
        }
        newPortfolio['usd'] -= cost;
        newPortfolio[coinSymbol] = (newPortfolio[coinSymbol] || 0) + amount;
      } else { // SELL
        if ((newPortfolio[coinSymbol] || 0) < amount) {
          alert(`Insufficient ${coin.symbol} balance.`);
          return p;
        }
        newPortfolio['usd'] += cost;
        newPortfolio[coinSymbol] -= amount;
      }
      orderPlaced = true;
      return newPortfolio;
    });

    if (orderPlaced) {
        const newOrder: Order = {
          id: Date.now(), coin, type, amount, status: 'FILLED',
          price: coin.current_price,
        };
        this.orders.update(o => [newOrder, ...o].slice(0, 50));
    }
  }

  private createLimitOrder(coin: Cryptocurrency, amount: number, type: TradeType, price: number) {
      const cost = amount * price;
      const coinSymbol = coin.symbol.toLowerCase();
      if (type === 'BUY' && this.portfolio()['usd'] < cost) {
          alert('Insufficient USD balance to place limit order.');
          return;
      }
      if (type === 'SELL' && (this.portfolio()[coinSymbol] || 0) < amount) {
          alert(`Insufficient ${coin.symbol} balance to place limit order.`);
          return;
      }

      const newOrder: Order = {
          id: Date.now(), coin, type, amount, price, status: 'OPEN'
      };
      this.orders.update(o => [newOrder, ...o].slice(0, 50));
  }

  private processOpenOrders(currentPrices: Map<string, number>) {
    const ordersToFill: Order[] = [];
    for (const order of this.orders()) {
        if (order.status !== 'OPEN') continue;

        const currentPrice = currentPrices.get(order.coin.id);
        if (currentPrice === undefined) continue;

        const shouldFill = 
            (order.type === 'BUY' && currentPrice <= order.price) ||
            (order.type === 'SELL' && currentPrice >= order.price);

        if (shouldFill) {
            ordersToFill.push(order);
        }
    }

    if (ordersToFill.length > 0) {
        this.portfolio.update(p => {
            const newPortfolio = {...p};
            ordersToFill.forEach((order, index) => {
                const coinSymbol = order.coin.symbol.toLowerCase();
                const cost = order.amount * order.price;
                if (order.type === 'BUY') {
                    if (newPortfolio['usd'] >= cost) {
                        newPortfolio['usd'] -= cost;
                        newPortfolio[coinSymbol] = (newPortfolio[coinSymbol] || 0) + order.amount;
                    } else {
                        ordersToFill.splice(index, 1);
                    }
                } else { // SELL
                    if ((newPortfolio[coinSymbol] || 0) >= order.amount) {
                        newPortfolio['usd'] += cost;
                        newPortfolio[coinSymbol] -= order.amount;
                    } else {
                        ordersToFill.splice(index, 1);
                    }
                }
            });
            return newPortfolio;
        });

        if (ordersToFill.length > 0) {
            const filledIds = new Set(ordersToFill.map(o => o.id));
            this.orders.update(currentOrders => 
                currentOrders.map(o => 
                    filledIds.has(o.id) ? { ...o, status: 'FILLED' } : o
                )
            );
        }
    }
  }

  formatCurrency(value: number): string {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 2, maximumFractionDigits: value < 1 ? 6 : 2 }).format(value);
  }

  formatNumber(value: number | undefined): string {
      if (value === undefined) return '0.0000';
      return value.toFixed(4);
  }
}

