import { ChangeDetectionStrategy, Component, computed, effect, inject, output, signal, PLATFORM_ID } from '@angular/core';
import { isPlatformBrowser, CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { CryptoService } from '../../services/crypto.service';
import { Cryptocurrency } from '../../models/crypto.model';
import { ChartComponent } from '../chart/chart.component';

type TradeType = 'BUY' | 'SELL';
type OrderType = 'MARKET' | 'LIMIT' | 'STOP';

interface Order {
  id: number;
  coin: Cryptocurrency;
  type: TradeType;
  orderType: OrderType;
  amount: number;
  price: number; // For LIMIT, this is the limit price. For STOP, this is the trigger price.
  status: 'OPEN' | 'FILLED' | 'CANCELLED';
  linkedOrderId?: number;
}

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CommonModule, FormsModule, ChartComponent]
})
export class DashboardComponent {
  logout = output<void>();

  cryptoService = inject(CryptoService);
  platformId = inject(PLATFORM_ID);
  allCoins = this.cryptoService.cryptoData;

  selectedCoin = signal<Cryptocurrency>(this.allCoins()[0]);
  isTradingActive = signal(true);

  tradeType = signal<TradeType>('BUY');
  orderType = signal<OrderType>('MARKET');
  tradeAmount = signal(0);
  limitPrice = signal(0);
  stopPrice = signal(0);

  // Automated Strategy Signals
  isStrategyEnabled = signal(false);
  stopLossPercent = signal(5);
  takeProfitPercent = signal(10);

  orders = signal<Order[]>([]);
  portfolio = signal<{ [key: string]: number }>({
    'usd': 10000, 'btc': 0, 'eth': 0, 'sol': 0, 'doge': 0
  });

  constructor() {
    if (isPlatformBrowser(this.platformId)) {
      const savedPortfolio = localStorage.getItem('crypto_portfolio');
      if (savedPortfolio) {
        this.portfolio.set(JSON.parse(savedPortfolio));
      }
      const savedOrders = localStorage.getItem('crypto_orders');
      if (savedOrders) {
        // Filter out any orders that might have been filled while offline for simplicity
        const loadedOrders: Order[] = JSON.parse(savedOrders);
        this.orders.set(loadedOrders);
      }
    }

    // Persist state to localStorage
    effect(() => {
      if (isPlatformBrowser(this.platformId)) {
        localStorage.setItem('crypto_portfolio', JSON.stringify(this.portfolio()));
        localStorage.setItem('crypto_orders', JSON.stringify(this.orders()));
      }
    });

    // Process open orders on price changes
    effect(() => {
        const coins = this.allCoins();
        if (this.orders().some(o => o.status === 'OPEN')) {
            const currentPrices: Map<string, number> = new Map(coins.map(c => [c.id, c.current_price]));
            this.processOpenOrders(currentPrices);
        }
    });
  }

  usdBalance = computed(() => this.portfolio()['usd']);
  assetBalance = computed(() => {
    const coinSymbol = this.selectedCoin().symbol.toLowerCase();
    return this.portfolio()[coinSymbol] || 0;
  });

  totalPortfolioValueUSD = computed(() => {
    const currentPortfolio = this.portfolio();
    const currentPrices = new Map(this.allCoins().map(c => [c.symbol.toLowerCase(), c.current_price]));

    let totalValue = currentPortfolio['usd'] || 0;

    for (const symbol in currentPortfolio) {
      if (symbol !== 'usd') {
        const amount = currentPortfolio[symbol];
        const price = currentPrices.get(symbol);
        // FIX: The price for a symbol from the portfolio might not be available in the current market data.
        // We must check if price is a valid number before using it in a calculation.
        if (amount > 0 && price !== undefined) {
          totalValue += amount * price;
        }
      }
    }

    return totalValue;
  });

  totalCost = computed(() => {
    const amount = this.tradeAmount();
    if (this.orderType() === 'LIMIT') {
        return amount * (this.limitPrice() || 0);
    }
    return amount * this.selectedCoin().current_price;
  });

  selectCoin(coin: Cryptocurrency) { this.selectedCoin.set(coin); }
  toggleTrading() { this.isTradingActive.update(active => !active); }
  setTradeType(type: TradeType) { this.tradeType.set(type); }
  setOrderType(type: OrderType) { this.orderType.set(type); }

  placeOrder() {
    const amount = this.tradeAmount();
    if (!amount || amount <= 0) return alert('Please enter a valid amount.');

    const currentOrderType = this.orderType();
    if (currentOrderType === 'LIMIT' && (!this.limitPrice() || this.limitPrice() <= 0)) return alert('Please enter a valid limit price.');
    if (currentOrderType === 'STOP' && (!this.stopPrice() || this.stopPrice() <= 0)) return alert('Please enter a valid stop price.');

    const coin = this.selectedCoin();
    const type = this.tradeType();

    if (currentOrderType === 'MARKET') {
        this.executeMarketOrder(coin, amount, type);
    } else {
        this.createOpenOrder(coin, amount, type, currentOrderType);
    }

    this.tradeAmount.set(0); this.limitPrice.set(0); this.stopPrice.set(0);
  }

  private createOpenOrder(coin: Cryptocurrency, amount: number, type: TradeType, orderType: 'LIMIT' | 'STOP') {
      const price = orderType === 'LIMIT' ? this.limitPrice() : this.stopPrice();
      const cost = amount * price;
      const coinSymbol = coin.symbol.toLowerCase();

      if (type === 'BUY' && this.portfolio()['usd'] < cost && orderType === 'LIMIT') return alert('Insufficient USD balance to place limit buy order.');
      if (type === 'SELL' && (this.portfolio()[coinSymbol] || 0) < amount) return alert(`Insufficient ${coin.symbol} balance to place order.`);

      const newOrder: Order = { id: Date.now(), coin, type, amount, price, status: 'OPEN', orderType };
      this.orders.update(o => [newOrder, ...o].slice(0, 100));
  }

  private executeTrade(order: {coin: Cryptocurrency, amount: number, type: TradeType, price: number}): boolean {
    let tradeExecuted = false;
    this.portfolio.update(p => {
        const newPortfolio = {...p};
        const coinSymbol = order.coin.symbol.toLowerCase();
        const cost = order.amount * order.price;

        if (order.type === 'BUY') {
            if (newPortfolio['usd'] < cost) return p;
            newPortfolio['usd'] -= cost;
            newPortfolio[coinSymbol] = (newPortfolio[coinSymbol] || 0) + order.amount;
        } else {
            if ((newPortfolio[coinSymbol] || 0) < order.amount) return p;
            newPortfolio['usd'] += cost;
            newPortfolio[coinSymbol] -= order.amount;
        }
        tradeExecuted = true;
        return newPortfolio;
    });
    return tradeExecuted;
  }

  private executeMarketOrder(coin: Cryptocurrency, amount: number, type: TradeType) {
    const order = { coin, amount, type, price: coin.current_price };
    const success = this.executeTrade(order);
    if (success) {
        const newOrder: Order = { id: Date.now(), ...order, status: 'FILLED', orderType: 'MARKET' };
        this.orders.update(o => [newOrder, ...o].slice(0, 100));
        if (type === 'BUY' && this.isStrategyEnabled()) {
            this.createAutomatedSellOrders(order.coin, order.amount, order.price);
        }
    } else {
        alert('Trade failed due to insufficient balance.');
    }
  }

  private createAutomatedSellOrders(coin: Cryptocurrency, amount: number, buyPrice: number) {
    const slPrice = buyPrice * (1 - this.stopLossPercent() / 100);
    const tpPrice = buyPrice * (1 + this.takeProfitPercent() / 100);

    const slOrderId = Date.now();
    const tpOrderId = slOrderId + 1;

    const stopLossOrder: Order = { id: slOrderId, coin, type: 'SELL', orderType: 'STOP', amount, price: slPrice, status: 'OPEN', linkedOrderId: tpOrderId };
    const takeProfitOrder: Order = { id: tpOrderId, coin, type: 'SELL', orderType: 'LIMIT', amount, price: tpPrice, status: 'OPEN', linkedOrderId: slOrderId };

    this.orders.update(o => [takeProfitOrder, stopLossOrder, ...o]);
  }

  cancelOrder(orderToCancel: Order) {
    const idsToCancel = new Set<number>([orderToCancel.id]);
    if (orderToCancel.linkedOrderId) {
        idsToCancel.add(orderToCancel.linkedOrderId);
    }
    this.orders.update(currentOrders => 
        currentOrders.map(o => 
            idsToCancel.has(o.id) && o.status === 'OPEN' ? { ...o, status: 'CANCELLED' } : o
        )
    );
  }

  private processOpenOrders(currentPrices: Map<string, number>) {
    const ordersToFill: Order[] = [];
    this.orders().forEach(order => {
        if (order.status !== 'OPEN') return;
        const currentPrice = currentPrices.get(order.coin.id);
        if (currentPrice === undefined) return;

        let shouldFill = false;
        if (order.orderType === 'LIMIT') shouldFill = (order.type === 'BUY' && currentPrice <= order.price) || (order.type === 'SELL' && currentPrice >= order.price);
        else if (order.orderType === 'STOP') shouldFill = (order.type === 'BUY' && currentPrice >= order.price) || (order.type === 'SELL' && currentPrice <= order.price);

        if (shouldFill) ordersToFill.push(order);
    });

    if (ordersToFill.length > 0) {
        const filledIds = new Set<number>();
        ordersToFill.forEach(order => {
            const executionPrice = order.orderType === 'STOP' ? currentPrices.get(order.coin.id)! : order.price;
            const success = this.executeTrade({ ...order, price: executionPrice });
            if (success) filledIds.add(order.id);
        });

        const cancelledIds = new Set<number>();
        ordersToFill.forEach(order => {
            if (filledIds.has(order.id) && order.linkedOrderId) {
                const linkedOrder = this.orders().find(o => o.id === order.linkedOrderId);
                if (linkedOrder?.status === 'OPEN') cancelledIds.add(order.linkedOrderId);
            }
        });

        if (filledIds.size > 0 || cancelledIds.size > 0) {
            this.orders.update(currentOrders => 
                currentOrders.map(o => {
                    if (filledIds.has(o.id)) return { ...o, status: 'FILLED' };
                    if (cancelledIds.has(o.id)) return { ...o, status: 'CANCELLED' };
                    return o;
                })
            );
        }
    }
  }

  formatCurrency(value: number): string {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 2, maximumFractionDigits: value < 1 ? 8 : 2 }).format(value);
  }

  formatNumber(value: number | undefined): string {
      if (value === undefined) return '0.0000';
      return value.toFixed(4);
  }
}

