import { ChangeDetectionStrategy, Component, computed, effect, inject, output, signal, PLATFORM_ID } from '@angular/core';
import { isPlatformBrowser, CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { CryptoService } from '../../services/crypto.service';
import { Cryptocurrency } from '../../models/crypto.model';
import { ChartComponent } from '../chart/chart.component';
import { GoogleGenAI, Type } from '@google/genai';
import { SimulatorComponent } from '../simulator/simulator.component';

type TradeType = 'BUY' | 'SELL';
type OrderType = 'MARKET' | 'LIMIT' | 'STOP';

interface Order {
  id: number;
  coin: Cryptocurrency;
  type: TradeType;
  orderType: OrderType;
  amount: number;
  price: number; // For LIMIT, this is the limit price. For STOP, this is the trigger price.
  status: 'OPEN' | 'FILLED' | 'CANCELLED';
  linkedOrderId?: number;
}

interface TradingRules {
  isSchedulerEnabled: boolean;
  dailyUsdLimit: number;
  spentToday: number;
  lastSpentDate: string;
  activeDays: boolean[];
  startTime: string;
  endTime: string;
}

interface PredictionResult {
    summary: string;
    confidence: number;
    rationale: string[];
}

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CommonModule, FormsModule, ChartComponent, SimulatorComponent]
})
export class DashboardComponent {
  logout = output<void>();

  cryptoService = inject(CryptoService);
  platformId = inject(PLATFORM_ID);

  allCoins = this.cryptoService.cryptoData;
  isTradingActive = signal(true);

  selectedCoin = signal<Cryptocurrency>(this.allCoins()[0]);

  tradeType = signal<TradeType>('BUY');
  orderType = signal<OrderType>('MARKET');
  tradeAmount = signal(0);
  limitPrice = signal(0);
  stopPrice = signal(0);

  // Automated Strategy Signals
  isStrategyEnabled = signal(false);
  stopLossPercent = signal(5);
  takeProfitPercent = signal(10);

  orders = signal<Order[]>([]);
  portfolio = signal<{ [key: string]: number }>({
    'usd': 10000, 'btc': 0, 'eth': 0, 'sol': 0, 'doge': 0
  });

  // --- Scheduled Trading Signals ---
  isSchedulerEnabled = signal(false);
  dailyUsdLimit = signal(1000);
  spentToday = signal(0);
  lastSpentDate = signal(new Date().toISOString().split('T')[0]); // YYYY-MM-DD
  activeDays = signal<boolean[]>([false, true, true, true, true, true, false]);
  startTime = signal('09:00');
  endTime = signal('17:00');
  weekDays = ['S', 'M', 'T', 'W', 'T', 'F', 'S'];

  // --- AI Prediction Signals ---
  isPredicting = signal(false);
  predictionResult = signal<PredictionResult | null>(null);

  // --- Simulator ---
  showSimulator = signal(false);

  constructor() {
    if (isPlatformBrowser(this.platformId)) {
      const savedPortfolio = localStorage.getItem('crypto_portfolio');
      if (savedPortfolio) this.portfolio.set(JSON.parse(savedPortfolio));

      const savedOrders = localStorage.getItem('crypto_orders');
      if (savedOrders) this.orders.set(JSON.parse(savedOrders));

      const savedRules = localStorage.getItem('crypto_trading_rules');
      if (savedRules) {
        const rules: TradingRules = JSON.parse(savedRules);
        this.isSchedulerEnabled.set(rules.isSchedulerEnabled);
        this.dailyUsdLimit.set(rules.dailyUsdLimit);
        this.activeDays.set(rules.activeDays);
        this.startTime.set(rules.startTime);
        this.endTime.set(rules.endTime);
        this.lastSpentDate.set(rules.lastSpentDate);
        this.spentToday.set(rules.spentToday);
      }

      const today = new Date().toISOString().split('T')[0];
      if (this.lastSpentDate() !== today) {
        this.spentToday.set(0);
        this.lastSpentDate.set(today);
      }
    }

    effect(() => {
      if (isPlatformBrowser(this.platformId)) {
        localStorage.setItem('crypto_portfolio', JSON.stringify(this.portfolio()));
        localStorage.setItem('crypto_orders', JSON.stringify(this.orders()));

        const rules: TradingRules = {
            isSchedulerEnabled: this.isSchedulerEnabled(),
            dailyUsdLimit: this.dailyUsdLimit(),
            spentToday: this.spentToday(),
            lastSpentDate: this.lastSpentDate(),
            activeDays: this.activeDays(),
            startTime: this.startTime(),
            endTime: this.endTime()
        };
        localStorage.setItem('crypto_trading_rules', JSON.stringify(rules));
      }
    });

    effect(() => {
        const coins = this.allCoins();
        if (this.orders().some(o => o.status === 'OPEN')) {
            const currentPrices: Map<string, number> = new Map(coins.map(c => [c.id, c.current_price]));
            this.processOpenOrders(currentPrices);
        }
    });
  }

  usdBalance = computed(() => this.portfolio()['usd']);
  assetBalance = computed(() => {
    const coinSymbol = this.selectedCoin().symbol.toLowerCase();
    return this.portfolio()[coinSymbol] || 0;
  });

  totalPortfolioValueUSD = computed(() => {
    const currentPortfolio = this.portfolio();
    const currentPrices = new Map(this.allCoins().map(c => [c.symbol.toLowerCase(), c.current_price]));
    let totalValue = currentPortfolio['usd'] || 0;
    for (const symbol in currentPortfolio) {
      if (symbol !== 'usd') {
        const amount = currentPortfolio[symbol];
        const price = currentPrices.get(symbol);
        if (amount > 0 && typeof price === 'number') {
          totalValue += amount * price;
        }
      }
    }
    return totalValue;
  });

  isTradingDay = computed(() => this.activeDays()[new Date().getDay()]);
  isTradingTime = computed(() => {
    const now = new Date();
    const currentTime = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;
    return currentTime >= this.startTime() && currentTime <= this.endTime();
  });
  isWithinSchedule = computed(() => !this.isSchedulerEnabled() || (this.isTradingDay() && this.isTradingTime()));
  isWithinLimit = computed(() => !this.isSchedulerEnabled() || this.spentToday() < this.dailyUsdLimit());
  canPlaceTrade = computed(() => this.isWithinSchedule() && this.isWithinLimit());
  tradingRestrictionReason = computed(() => {
    if (!this.isSchedulerEnabled() || this.canPlaceTrade()) return '';
    if (!this.isTradingDay()) return 'Trading is disabled for today.';
    if (!this.isTradingTime()) return `Trading is only allowed between ${this.startTime()} and ${this.endTime()}.`;
    if (!this.isWithinLimit()) return `Daily USD limit reached. Spent: ${this.formatCurrency(this.spentToday())}.`;
    return 'Trading is currently restricted by your rules.';
  });

  totalCost = computed(() => {
    const amount = this.tradeAmount();
    if (this.orderType() === 'LIMIT') return amount * (this.limitPrice() || 0);
    return amount * this.selectedCoin().current_price;
  });

  selectCoin(coin: Cryptocurrency) {
    this.selectedCoin.set(coin);
    this.predictionResult.set(null); // Reset prediction when coin changes
  }
  toggleTrading() { this.isTradingActive.update(active => !active); }
  setTradeType(type: TradeType) { this.tradeType.set(type); }
  setOrderType(type: OrderType) { this.orderType.set(type); }
  toggleActiveDay(index: number) {
    this.activeDays.update(days => {
        const newDays = [...days];
        newDays[index] = !newDays[index];
        return newDays;
    });
  }

  placeOrder() {
    if (this.isSchedulerEnabled() && !this.canPlaceTrade()) {
      return alert(this.tradingRestrictionReason());
    }
    const amount = this.tradeAmount();
    if (!amount || amount <= 0) return alert('Please enter a valid amount.');
    const orderType = this.orderType();
    if (orderType === 'LIMIT' && (!this.limitPrice() || this.limitPrice() <= 0)) return alert('Please enter a valid limit price.');
    if (orderType === 'STOP' && (!this.stopPrice() || this.stopPrice() <= 0)) return alert('Please enter a valid stop price.');

    if (orderType === 'MARKET') {
      this.executeMarketOrder(this.selectedCoin(), amount, this.tradeType());
    } else {
      this.createOpenOrder(this.selectedCoin(), amount, this.tradeType(), orderType);
    }
    this.tradeAmount.set(0); this.limitPrice.set(0); this.stopPrice.set(0);
  }

  private createOpenOrder(coin: Cryptocurrency, amount: number, type: TradeType, orderType: 'LIMIT' | 'STOP') {
      const price = orderType === 'LIMIT' ? this.limitPrice() : this.stopPrice();
      const cost = amount * price;
      const coinSymbol = coin.symbol.toLowerCase();

      if (type === 'BUY' && this.portfolio()['usd'] < cost && orderType === 'LIMIT') return alert('Insufficient USD balance for limit buy.');
      if (type === 'SELL' && (this.portfolio()[coinSymbol] || 0) < amount) return alert(`Insufficient ${coin.symbol} balance.`);

      const newOrder: Order = { id: Date.now(), coin, type, amount, price, status: 'OPEN', orderType };
      this.orders.update(o => [newOrder, ...o].slice(0, 100));
  }

  private executeTrade(order: {coin: Cryptocurrency, amount: number, type: TradeType, price: number}): { success: boolean, message?: string } {
    const currentPortfolio = this.portfolio();
    const coinSymbol = order.coin.symbol.toLowerCase();
    const cost = order.amount * order.price;

    if (order.type === 'BUY') {
        const usdBalance = currentPortfolio['usd'];
        if (usdBalance < cost) return { success: false, message: `Insufficient USD. Required: ${this.formatCurrency(cost)}, Have: ${this.formatCurrency(usdBalance)}.` };
    } else {
        const assetBalance = currentPortfolio[coinSymbol] || 0;
        if (assetBalance < order.amount) return { success: false, message: `Insufficient ${order.coin.symbol.toUpperCase()}. Required: ${this.formatNumber(order.amount)}, Have: ${this.formatNumber(assetBalance)}.` };
    }

    let wasSuccessful = false;
    this.portfolio.update(p => {
        const newPortfolio = {...p};
        if (order.type === 'BUY' && p['usd'] >= cost) {
            newPortfolio['usd'] -= cost;
            newPortfolio[coinSymbol] = (newPortfolio[coinSymbol] || 0) + order.amount;
            wasSuccessful = true; return newPortfolio;
        }
        if (order.type === 'SELL' && (p[coinSymbol] || 0) >= order.amount) {
            newPortfolio['usd'] += cost;
            newPortfolio[coinSymbol] -= order.amount;
            wasSuccessful = true; return newPortfolio;
        }
        return p;
    });

    if (wasSuccessful) return { success: true };
    return { success: false, message: 'Trade failed. Balance may have changed.' };
  }

  private executeMarketOrder(coin: Cryptocurrency, amount: number, type: TradeType) {
    const order = { coin, amount, type, price: coin.current_price };
    const cost = order.price * order.amount;

    if (type === 'BUY' && this.isSchedulerEnabled() && (this.spentToday() + cost) > this.dailyUsdLimit()) {
      return alert(`This trade would exceed your daily limit. Limit: ${this.formatCurrency(this.dailyUsdLimit())}, Spent: ${this.formatCurrency(this.spentToday())}, Cost: ${this.formatCurrency(cost)}`);
    }

    const result = this.executeTrade(order);
    if (result.success) {
      if (type === 'BUY') this.spentToday.update(spent => spent + cost);
      const newOrder: Order = { id: Date.now(), ...order, status: 'FILLED', orderType: 'MARKET' };
      this.orders.update(o => [newOrder, ...o].slice(0, 100));
      if (type === 'BUY' && this.isStrategyEnabled()) {
        this.createAutomatedSellOrders(order.coin, order.amount, order.price);
      }
    } else {
      alert(result.message || 'Trade failed due to an unknown error.');
    }
  }

  private createAutomatedSellOrders(coin: Cryptocurrency, amount: number, buyPrice: number) {
    const slPrice = buyPrice * (1 - this.stopLossPercent() / 100);
    const tpPrice = buyPrice * (1 + this.takeProfitPercent() / 100);
    const slOrderId = Date.now(), tpOrderId = slOrderId + 1;
    const stopLossOrder: Order = { id: slOrderId, coin, type: 'SELL', orderType: 'STOP', amount, price: slPrice, status: 'OPEN', linkedOrderId: tpOrderId };
    const takeProfitOrder: Order = { id: tpOrderId, coin, type: 'SELL', orderType: 'LIMIT', amount, price: tpPrice, status: 'OPEN', linkedOrderId: slOrderId };
    this.orders.update(o => [takeProfitOrder, stopLossOrder, ...o]);
  }

  cancelOrder(orderToCancel: Order) {
    const idsToCancel = new Set<number>([orderToCancel.id]);
    if (orderToCancel.linkedOrderId) idsToCancel.add(orderToCancel.linkedOrderId);
    this.orders.update(currentOrders => currentOrders.map(o => idsToCancel.has(o.id) && o.status === 'OPEN' ? { ...o, status: 'CANCELLED' } : o));
  }

  private processOpenOrders(currentPrices: Map<string, number>) {
    const ordersToFill: Order[] = [];
    this.orders().forEach(order => {
        if (order.status !== 'OPEN') return;
        const currentPrice = currentPrices.get(order.coin.id);
        if (currentPrice === undefined) return;

        let shouldFill = false;
        if (order.orderType === 'LIMIT') shouldFill = (order.type === 'BUY' && currentPrice <= order.price) || (order.type === 'SELL' && currentPrice >= order.price);
        else if (order.orderType === 'STOP') shouldFill = (order.type === 'BUY' && currentPrice >= order.price) || (order.type === 'SELL' && currentPrice <= order.price);

        if (shouldFill) {
            if (order.type === 'BUY' && this.isSchedulerEnabled() && !this.canPlaceTrade()) return;
            ordersToFill.push(order);
        }
    });

    if (ordersToFill.length > 0) {
        const filledIds = new Set<number>();
        ordersToFill.forEach(order => {
            const executionPrice = order.orderType === 'STOP' ? currentPrices.get(order.coin.id)! : order.price;
            const cost = executionPrice * order.amount;

            if (order.type === 'BUY' && this.isSchedulerEnabled() && (this.spentToday() + cost > this.dailyUsdLimit())) return;

            const result = this.executeTrade({ ...order, price: executionPrice });
            if (result.success) {
                if (order.type === 'BUY') this.spentToday.update(spent => spent + cost);
                filledIds.add(order.id);
            }
        });

        const cancelledIds = new Set<number>();
        ordersToFill.forEach(order => {
            if (filledIds.has(order.id) && order.linkedOrderId) {
                const linkedOrder = this.orders().find(o => o.id === order.linkedOrderId);
                if (linkedOrder?.status === 'OPEN') cancelledIds.add(order.linkedOrderId);
            }
        });

        if (filledIds.size > 0 || cancelledIds.size > 0) {
            this.orders.update(currentOrders => currentOrders.map(o => {
                if (filledIds.has(o.id)) return { ...o, status: 'FILLED' };
                if (cancelledIds.has(o.id)) return { ...o, status: 'CANCELLED' };
                return o;
            }));
        }
    }
  }

  async getAiPrediction() {
    this.isPredicting.set(true);
    this.predictionResult.set(null);
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
        const coin = this.selectedCoin();
        const priceHistory = coin.price_history.map(p => this.formatCurrency(p)).join(', ');
        const prompt = `
            You are a crypto market analyst providing a short-term prediction (next few hours) for ${coin.name} (${coin.symbol}).
            Current Data:
            - Price: ${this.formatCurrency(coin.current_price)}
            - 24h Change: ${coin.price_change_percentage_24h.toFixed(2)}%
            - Recent Price History (oldest to newest): ${priceHistory}

            Based *only* on this data, provide your analysis in the specified JSON format. The summary should be one of these: Bullish, Bearish, Stable, or Volatile.
        `;

        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        summary: { type: Type.STRING, description: 'The overall market sentiment prediction.' },
                        confidence: { type: Type.INTEGER, description: 'Confidence in the prediction, from 0 to 100.' },
                        rationale: { type: Type.ARRAY, items: { type: Type.STRING }, description: 'Brief reasons for the prediction.' }
                    },
                    required: ["summary", "confidence", "rationale"]
                },
            },
        });

        const resultText = response.text.trim();
        this.predictionResult.set(JSON.parse(resultText));

    } catch (error) {
        console.error("AI Prediction failed:", error);
        alert("Failed to get AI prediction. Please check the console for details.");
    } finally {
        this.isPredicting.set(false);
    }
  }

  formatCurrency(value: number): string {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 2, maximumFractionDigits: value < 1 ? 8 : 2 }).format(value);
  }

  formatNumber(value: number | undefined): string {
      if (value === undefined) return '0.0000';
      return value.toFixed(4);
  }
}

import { ChangeDetectionStrategy, Component, OnDestroy, computed, inject, output, signal } from '@angular/core';
import { CryptoService } from '../../services/crypto.service';
import { Cryptocurrency } from '../../models/crypto.model';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { GoogleGenAI, Type } from '@google/genai';

type TradeType = 'BUY' | 'SELL';

interface SimOrder {
  id: number;
  coin: Cryptocurrency;
  type: TradeType;
  amount: number;
  price: number;
  cost: number;
}

interface SuggestedSettings {
    strategyName: string;
    rationale: string;
    simulationSpeed: number;
    maxTradeUsd: number;
}


@Component({
  selector: 'app-simulator',
  templateUrl: './simulator.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CommonModule, FormsModule]
})
export class SimulatorComponent implements OnDestroy {
  close = output<void>();
  cryptoService = inject(CryptoService);

  // --- State ---
  isActive = signal(false);
  portfolio = signal<{ [key: string]: number }>({ 'usd': 10000 });
  tradeLog = signal<SimOrder[]>([]);
  private intervalId: any;

  // --- Configuration ---
  simulationSpeed = signal(1000); // ms between trades
  maxTradeUsd = signal(500); // max USD value of a single trade

  // --- AI Suggestions ---
  isSuggesting = signal(false);
  suggestedSettings = signal<SuggestedSettings | null>(null);

  allCoins = this.cryptoService.cryptoData;

  constructor() {
  }

  ngOnDestroy(): void {
    this.stop();
  }

  start() {
    if (this.isActive()) return;
    this.isActive.set(true);
    this.intervalId = setInterval(() => this.runSimulationTick(), this.simulationSpeed());
  }

  stop() {
    this.isActive.set(false);
    if (this.intervalId) {
      clearInterval(this.intervalId);
      this.intervalId = null;
    }
  }

  onSpeedChange() {
    if (this.isActive()) {
      this.stop();
      this.start();
    }
  }

  private runSimulationTick() {
    const coins = this.allCoins();
    if (coins.length === 0) return;

    // 1. Pick a random coin
    const coin = coins[Math.floor(Math.random() * coins.length)];
    const coinSymbol = coin.symbol.toLowerCase();

    // 2. Decide to buy or sell (simple 50/50 logic)
    const tradeType: TradeType = Math.random() > 0.5 ? 'BUY' : 'SELL';

    const usdBalance = this.portfolio()['usd'] || 0;
    const assetBalance = this.portfolio()[coinSymbol] || 0;

    if (tradeType === 'BUY') {
      if (usdBalance < 10) return; // Not enough money to make a meaningful trade
      const tradeValue = Math.random() * Math.min(this.maxTradeUsd(), usdBalance);
      if (tradeValue < 1) return; // Too small

      const amount = tradeValue / coin.current_price;
      this.executeTrade(coin, amount, 'BUY');

    } else { // SELL
      if (assetBalance <= 0) return; // Nothing to sell
      const amountToSell = Math.random() * assetBalance;
       if (amountToSell * coin.current_price < 1) return; // Too small

      this.executeTrade(coin, amountToSell, 'SELL');
    }
  }

  private executeTrade(coin: Cryptocurrency, amount: number, type: TradeType) {
      const coinSymbol = coin.symbol.toLowerCase();
      const price = coin.current_price;
      const cost = amount * price;

      this.portfolio.update(p => {
          const newPortfolio = {...p};
          if (type === 'BUY') {
              newPortfolio['usd'] -= cost;
              newPortfolio[coinSymbol] = (newPortfolio[coinSymbol] || 0) + amount;
          } else { // SELL
              newPortfolio['usd'] += cost;
              newPortfolio[coinSymbol] -= amount;
          }
          return newPortfolio;
      });

      const logEntry: SimOrder = { id: Date.now(), coin, type, amount, price, cost };
      this.tradeLog.update(log => [logEntry, ...log].slice(0, 100));
  }

  async getAiSuggestedSettings() {
    this.isSuggesting.set(true);
    this.suggestedSettings.set(null);
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
        const marketData = this.allCoins().map(c => 
            `- ${c.name}: Price=${this.formatCurrency(c.current_price)}, 24h Change=${c.price_change_percentage_24h.toFixed(2)}%`
        ).join('\n');

        const prompt = `
            You are a trading bot strategist. Based on the following crypto market data, suggest optimal settings for a trading simulator.
            The available settings are 'simulationSpeed' (time in ms between trades, 500-3000) and 'maxTradeUsd' (max USD value per trade, 50-2000).
            - A lower speed (e.g., 500ms) is aggressive. A higher speed (e.g., 2500ms) is conservative.
            - A higher max trade size is riskier.

            Current Market Data:
            ${marketData}

            Analyze the overall market sentiment (e.g., volatile, bullish, bearish, stable) from the data and provide settings that fit that sentiment.
            Return your response in the specified JSON format.
        `;

        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        strategyName: { type: Type.STRING, description: 'A creative name for the trading strategy.' },
                        rationale: { type: Type.STRING, description: 'A brief explanation for the chosen settings based on market data.' },
                        simulationSpeed: { type: Type.INTEGER, description: 'The suggested speed in milliseconds.' },
                        maxTradeUsd: { type: Type.INTEGER, description: 'The suggested max trade size in USD.' },
                    },
                    required: ["strategyName", "rationale", "simulationSpeed", "maxTradeUsd"]
                },
            },
        });

        const resultText = response.text.trim();
        this.suggestedSettings.set(JSON.parse(resultText));

    } catch (error) {
        console.error("AI Suggestion failed:", error);
        alert("Failed to get AI-suggested settings. Please check the console.");
    } finally {
        this.isSuggesting.set(false);
    }
  }

  applySuggestedSettings() {
    const settings = this.suggestedSettings();
    if (settings) {
      this.simulationSpeed.set(settings.simulationSpeed);
      this.maxTradeUsd.set(settings.maxTradeUsd);
      this.suggestedSettings.set(null); // Hide after applying
    }
  }

  totalPortfolioValueUSD = computed(() => {
    const currentPortfolio = this.portfolio();
    const currentPrices = new Map(this.allCoins().map(c => [c.symbol.toLowerCase(), c.current_price]));
    let totalValue = currentPortfolio['usd'] || 0;
    for (const symbol in currentPortfolio) {
      if (symbol !== 'usd') {
        const amount = currentPortfolio[symbol];
        const price = currentPrices.get(symbol);
        if (amount > 0 && typeof price === 'number') {
          totalValue += amount * price;
        }
      }
    }
    return totalValue;
  });

  formatCurrency(value: number): string {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(value);
  }

  formatNumber(value: number | undefined): string {
      if (value === undefined) return '0.0000';
      return value.toFixed(4);
  }
}

import { ChangeDetectionStrategy, Component, computed, effect, inject, output, signal, PLATFORM_ID } from '@angular/core';
import { isPlatformBrowser, CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { CryptoService } from '../../services/crypto.service';
import { Cryptocurrency } from '../../models/crypto.model';
import { ChartComponent } from '../chart/chart.component';
import { GoogleGenAI, Type } from '@google/genai';
import { SimulatorComponent } from '../simulator/simulator.component';

type TradeType = 'BUY' | 'SELL';
type OrderType = 'MARKET' | 'LIMIT' | 'STOP';

interface Order {
  id: number;
  coin: Cryptocurrency;
  type: TradeType;
  orderType: OrderType;
  amount: number;
  price: number; // For LIMIT, this is the limit price. For STOP, this is the trigger price.
  status: 'OPEN' | 'FILLED' | 'CANCELLED';
  linkedOrderId?: number;
}

interface TradingRules {
  isSchedulerEnabled: boolean;
  dailyUsdLimit: number;
  spentToday: number;
  lastSpentDate: string;
  activeDays: boolean[];
  startTime: string;
  endTime: string;
}

interface PredictionResult {
    summary: string;
    confidence: number;
    rationale: string[];
}

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CommonModule, FormsModule, ChartComponent, SimulatorComponent]
})
export class DashboardComponent {
  logout = output<void>();

  cryptoService = inject(CryptoService);
  platformId = inject(PLATFORM_ID);

  allCoins = this.cryptoService.cryptoData;
  isTradingActive = signal(true);

  selectedCoin = signal<Cryptocurrency>(this.allCoins()[0]);

  tradeType = signal<TradeType>('BUY');
  orderType = signal<OrderType>('MARKET');
  tradeAmount = signal(0);
  limitPrice = signal(0);
  stopPrice = signal(0);

  // Automated Strategy Signals
  isStrategyEnabled = signal(false);
  stopLossPercent = signal(5);
  takeProfitPercent = signal(10);

  orders = signal<Order[]>([]);
  portfolio = signal<{ [key: string]: number }>({
    'usd': 10000, 'btc': 0, 'eth': 0, 'sol': 0, 'doge': 0
  });

  // --- Scheduled Trading Signals ---
  isSchedulerEnabled = signal(false);
  dailyUsdLimit = signal(1000);
  spentToday = signal(0);
  lastSpentDate = signal(new Date().toISOString().split('T')[0]); // YYYY-MM-DD
  activeDays = signal<boolean[]>([false, true, true, true, true, true, false]);
  startTime = signal('09:00');
  endTime = signal('17:00');
  weekDays = ['S', 'M', 'T', 'W', 'T', 'F', 'S'];

  // --- AI Prediction Signals ---
  isPredicting = signal(false);
  predictionResult = signal<PredictionResult | null>(null);

  // --- Simulator ---
  showSimulator = signal(false);

  constructor() {
    if (isPlatformBrowser(this.platformId)) {
      const savedPortfolio = localStorage.getItem('crypto_portfolio');
      if (savedPortfolio) this.portfolio.set(JSON.parse(savedPortfolio));

      const savedOrders = localStorage.getItem('crypto_orders');
      if (savedOrders) this.orders.set(JSON.parse(savedOrders));

      const savedRules = localStorage.getItem('crypto_trading_rules');
      if (savedRules) {
        const rules: TradingRules = JSON.parse(savedRules);
        this.isSchedulerEnabled.set(rules.isSchedulerEnabled);
        this.dailyUsdLimit.set(rules.dailyUsdLimit);
        this.activeDays.set(rules.activeDays);
        this.startTime.set(rules.startTime);
        this.endTime.set(rules.endTime);
        this.lastSpentDate.set(rules.lastSpentDate);
        this.spentToday.set(rules.spentToday);
      }

      const today = new Date().toISOString().split('T')[0];
      if (this.lastSpentDate() !== today) {
        this.spentToday.set(0);
        this.lastSpentDate.set(today);
      }
    }

    effect(() => {
      if (isPlatformBrowser(this.platformId)) {
        localStorage.setItem('crypto_portfolio', JSON.stringify(this.portfolio()));
        localStorage.setItem('crypto_orders', JSON.stringify(this.orders()));

        const rules: TradingRules = {
            isSchedulerEnabled: this.isSchedulerEnabled(),
            dailyUsdLimit: this.dailyUsdLimit(),
            spentToday: this.spentToday(),
            lastSpentDate: this.lastSpentDate(),
            activeDays: this.activeDays(),
            startTime: this.startTime(),
            endTime: this.endTime()
        };
        localStorage.setItem('crypto_trading_rules', JSON.stringify(rules));
      }
    });

    effect(() => {
        const coins = this.allCoins();
        if (this.orders().some(o => o.status === 'OPEN')) {
            const currentPrices: Map<string, number> = new Map(coins.map(c => [c.id, c.current_price]));
            this.processOpenOrders(currentPrices);
        }
    });
  }

  usdBalance = computed(() => this.portfolio()['usd']);
  assetBalance = computed(() => {
    const coinSymbol = this.selectedCoin().symbol.toLowerCase();
    return this.portfolio()[coinSymbol] || 0;
  });

  totalPortfolioValueUSD = computed(() => {
    const currentPortfolio = this.portfolio();
    const currentPrices = new Map(this.allCoins().map(c => [c.symbol.toLowerCase(), c.current_price]));
    let totalValue = currentPortfolio['usd'] || 0;
    for (const symbol in currentPortfolio) {
      if (symbol !== 'usd') {
        const amount = currentPortfolio[symbol];
        const price = currentPrices.get(symbol);
        if (amount > 0 && typeof price === 'number') {
          totalValue += amount * price;
        }
      }
    }
    return totalValue;
  });

  isTradingDay = computed(() => this.activeDays()[new Date().getDay()]);
  isTradingTime = computed(() => {
    const now = new Date();
    const currentTime = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;
    return currentTime >= this.startTime() && currentTime <= this.endTime();
  });
  isWithinSchedule = computed(() => !this.isSchedulerEnabled() || (this.isTradingDay() && this.isTradingTime()));
  isWithinLimit = computed(() => !this.isSchedulerEnabled() || this.spentToday() < this.dailyUsdLimit());
  canPlaceTrade = computed(() => this.isWithinSchedule() && this.isWithinLimit());
  tradingRestrictionReason = computed(() => {
    if (!this.isSchedulerEnabled() || this.canPlaceTrade()) return '';
    if (!this.isTradingDay()) return 'Trading is disabled for today.';
    if (!this.isTradingTime()) return `Trading is only allowed between ${this.startTime()} and ${this.endTime()}.`;
    if (!this.isWithinLimit()) return `Daily USD limit reached. Spent: ${this.formatCurrency(this.spentToday())}.`;
    return 'Trading is currently restricted by your rules.';
  });

  totalCost = computed(() => {
    const amount = this.tradeAmount();
    if (this.orderType() === 'LIMIT') return amount * (this.limitPrice() || 0);
    return amount * this.selectedCoin().current_price;
  });

  selectCoin(coin: Cryptocurrency) {
    this.selectedCoin.set(coin);
    this.predictionResult.set(null); // Reset prediction when coin changes
  }
  toggleTrading() { this.isTradingActive.update(active => !active); }
  setTradeType(type: TradeType) { this.tradeType.set(type); }
  setOrderType(type: OrderType) { this.orderType.set(type); }
  toggleActiveDay(index: number) {
    this.activeDays.update(days => {
        const newDays = [...days];
        newDays[index] = !newDays[index];
        return newDays;
    });
  }

  placeOrder() {
    if (this.isSchedulerEnabled() && !this.canPlaceTrade()) {
      return alert(this.tradingRestrictionReason());
    }
    const amount = this.tradeAmount();
    if (!amount || amount <= 0) return alert('Please enter a valid amount.');
    const orderType = this.orderType();
    if (orderType === 'LIMIT' && (!this.limitPrice() || this.limitPrice() <= 0)) return alert('Please enter a valid limit price.');
    if (orderType === 'STOP' && (!this.stopPrice() || this.stopPrice() <= 0)) return alert('Please enter a valid stop price.');

    if (orderType === 'MARKET') {
      this.executeMarketOrder(this.selectedCoin(), amount, this.tradeType());
    } else {
      this.createOpenOrder(this.selectedCoin(), amount, this.tradeType(), orderType);
    }
    this.tradeAmount.set(0); this.limitPrice.set(0); this.stopPrice.set(0);
  }

  private createOpenOrder(coin: Cryptocurrency, amount: number, type: TradeType, orderType: 'LIMIT' | 'STOP') {
      const price = orderType === 'LIMIT' ? this.limitPrice() : this.stopPrice();
      const cost = amount * price;
      const coinSymbol = coin.symbol.toLowerCase();

      if (type === 'BUY' && this.portfolio()['usd'] < cost && orderType === 'LIMIT') return alert('Insufficient USD balance for limit buy.');
      if (type === 'SELL' && (this.portfolio()[coinSymbol] || 0) < amount) return alert(`Insufficient ${coin.symbol} balance.`);

      const newOrder: Order = { id: Date.now(), coin, type, amount, price, status: 'OPEN', orderType };
      this.orders.update(o => [newOrder, ...o].slice(0, 100));
  }

  private executeTrade(order: {coin: Cryptocurrency, amount: number, type: TradeType, price: number}): { success: boolean, message?: string } {
    const currentPortfolio = this.portfolio();
    const coinSymbol = order.coin.symbol.toLowerCase();
    const cost = order.amount * order.price;

    if (order.type === 'BUY') {
        const usdBalance = currentPortfolio['usd'];
        if (usdBalance < cost) return { success: false, message: `Insufficient USD. Required: ${this.formatCurrency(cost)}, Have: ${this.formatCurrency(usdBalance)}.` };
    } else {
        const assetBalance = currentPortfolio[coinSymbol] || 0;
        if (assetBalance < order.amount) return { success: false, message: `Insufficient ${order.coin.symbol.toUpperCase()}. Required: ${this.formatNumber(order.amount)}, Have: ${this.formatNumber(assetBalance)}.` };
    }

    let wasSuccessful = false;
    this.portfolio.update(p => {
        const newPortfolio = {...p};
        if (order.type === 'BUY' && p['usd'] >= cost) {
            newPortfolio['usd'] -= cost;
            newPortfolio[coinSymbol] = (newPortfolio[coinSymbol] || 0) + order.amount;
            wasSuccessful = true; return newPortfolio;
        }
        if (order.type === 'SELL' && (p[coinSymbol] || 0) >= order.amount) {
            newPortfolio['usd'] += cost;
            newPortfolio[coinSymbol] -= order.amount;
            wasSuccessful = true; return newPortfolio;
        }
        return p;
    });

    if (wasSuccessful) return { success: true };
    return { success: false, message: 'Trade failed. Balance may have changed.' };
  }

  private executeMarketOrder(coin: Cryptocurrency, amount: number, type: TradeType) {
    const order = { coin, amount, type, price: coin.current_price };
    const cost = order.price * order.amount;

    if (type === 'BUY' && this.isSchedulerEnabled() && (this.spentToday() + cost) > this.dailyUsdLimit()) {
      return alert(`This trade would exceed your daily limit. Limit: ${this.formatCurrency(this.dailyUsdLimit())}, Spent: ${this.formatCurrency(this.spentToday())}, Cost: ${this.formatCurrency(cost)}`);
    }

    const result = this.executeTrade(order);
    if (result.success) {
      if (type === 'BUY') this.spentToday.update(spent => spent + cost);
      const newOrder: Order = { id: Date.now(), ...order, status: 'FILLED', orderType: 'MARKET' };
      this.orders.update(o => [newOrder, ...o].slice(0, 100));
      if (type === 'BUY' && this.isStrategyEnabled()) {
        this.createAutomatedSellOrders(order.coin, order.amount, order.price);
      }
    } else {
      alert(result.message || 'Trade failed due to an unknown error.');
    }
  }

  private createAutomatedSellOrders(coin: Cryptocurrency, amount: number, buyPrice: number) {
    const slPrice = buyPrice * (1 - this.stopLossPercent() / 100);
    const tpPrice = buyPrice * (1 + this.takeProfitPercent() / 100);
    const slOrderId = Date.now(), tpOrderId = slOrderId + 1;
    const stopLossOrder: Order = { id: slOrderId, coin, type: 'SELL', orderType: 'STOP', amount, price: slPrice, status: 'OPEN', linkedOrderId: tpOrderId };
    const takeProfitOrder: Order = { id: tpOrderId, coin, type: 'SELL', orderType: 'LIMIT', amount, price: tpPrice, status: 'OPEN', linkedOrderId: slOrderId };
    this.orders.update(o => [takeProfitOrder, stopLossOrder, ...o]);
  }

  cancelOrder(orderToCancel: Order) {
    const idsToCancel = new Set<number>([orderToCancel.id]);
    if (orderToCancel.linkedOrderId) idsToCancel.add(orderToCancel.linkedOrderId);
    this.orders.update(currentOrders => currentOrders.map(o => idsToCancel.has(o.id) && o.status === 'OPEN' ? { ...o, status: 'CANCELLED' } : o));
  }

  private processOpenOrders(currentPrices: Map<string, number>) {
    const ordersToFill: Order[] = [];
    this.orders().forEach(order => {
        if (order.status !== 'OPEN') return;
        const currentPrice = currentPrices.get(order.coin.id);
        if (currentPrice === undefined) return;

        let shouldFill = false;
        if (order.orderType === 'LIMIT') shouldFill = (order.type === 'BUY' && currentPrice <= order.price) || (order.type === 'SELL' && currentPrice >= order.price);
        else if (order.orderType === 'STOP') shouldFill = (order.type === 'BUY' && currentPrice >= order.price) || (order.type === 'SELL' && currentPrice <= order.price);

        if (shouldFill) {
            if (order.type === 'BUY' && this.isSchedulerEnabled() && !this.canPlaceTrade()) return;
            ordersToFill.push(order);
        }
    });

    if (ordersToFill.length > 0) {
        const filledIds = new Set<number>();
        ordersToFill.forEach(order => {
            const executionPrice = order.orderType === 'STOP' ? currentPrices.get(order.coin.id)! : order.price;
            const cost = executionPrice * order.amount;

            if (order.type === 'BUY' && this.isSchedulerEnabled() && (this.spentToday() + cost > this.dailyUsdLimit())) return;

            const result = this.executeTrade({ ...order, price: executionPrice });
            if (result.success) {
                if (order.type === 'BUY') this.spentToday.update(spent => spent + cost);
                filledIds.add(order.id);
            }
        });

        const cancelledIds = new Set<number>();
        ordersToFill.forEach(order => {
            if (filledIds.has(order.id) && order.linkedOrderId) {
                const linkedOrder = this.orders().find(o => o.id === order.linkedOrderId);
                if (linkedOrder?.status === 'OPEN') cancelledIds.add(order.linkedOrderId);
            }
        });

        if (filledIds.size > 0 || cancelledIds.size > 0) {
            this.orders.update(currentOrders => currentOrders.map(o => {
                if (filledIds.has(o.id)) return { ...o, status: 'FILLED' };
                if (cancelledIds.has(o.id)) return { ...o, status: 'CANCELLED' };
                return o;
            }));
        }
    }
  }

  async getAiPrediction() {
    this.isPredicting.set(true);
    this.predictionResult.set(null);
    try {
        const ai = new GoogleGenAI({ apiKey: (globalThis as any).process.env.API_KEY as string });
        const coin = this.selectedCoin();
        const priceHistory = coin.price_history.map(p => this.formatCurrency(p)).join(', ');
        const prompt = `
            You are a crypto market analyst providing a short-term prediction (next few hours) for ${coin.name} (${coin.symbol}).
            Current Data:
            - Price: ${this.formatCurrency(coin.current_price)}
            - 24h Change: ${coin.price_change_percentage_24h.toFixed(2)}%
            - Recent Price History (oldest to newest): ${priceHistory}

            Based *only* on this data, provide your analysis in the specified JSON format. The summary should be one of these: Bullish, Bearish, Stable, or Volatile.
        `;

        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        summary: { type: Type.STRING, description: 'The overall market sentiment prediction.' },
                        confidence: { type: Type.INTEGER, description: 'Confidence in the prediction, from 0 to 100.' },
                        rationale: { type: Type.ARRAY, items: { type: Type.STRING }, description: 'Brief reasons for the prediction.' }
                    },
                    required: ["summary", "confidence", "rationale"]
                },
            },
        });

        const resultText = response.text.trim();
        this.predictionResult.set(JSON.parse(resultText));

    } catch (error) {
        console.error("AI Prediction failed:", error);
        alert("Failed to get AI prediction. Please check the console for details.");
    } finally {
        this.isPredicting.set(false);
    }
  }

  formatCurrency(value: number): string {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 2, maximumFractionDigits: value < 1 ? 8 : 2 }).format(value);
  }

  formatNumber(value: number | undefined): string {
      if (value === undefined) return '0.0000';
      return value.toFixed(4);
  }
}

import { ChangeDetectionStrategy, Component, OnDestroy, computed, inject, output, signal } from '@angular/core';
import { CryptoService } from '../../services/crypto.service';
import { Cryptocurrency } from '../../models/crypto.model';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { GoogleGenAI, Type } from '@google/genai';

type TradeType = 'BUY' | 'SELL';

interface SimOrder {
  id: number;
  coin: Cryptocurrency;
  type: TradeType;
  amount: number;
  price: number;
  cost: number;
}

interface SuggestedSettings {
    strategyName: string;
    rationale: string;
    simulationSpeed: number;
    maxTradeUsd: number;
}


@Component({
  selector: 'app-simulator',
  templateUrl: './simulator.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CommonModule, FormsModule]
})
export class SimulatorComponent implements OnDestroy {
  close = output<void>();
  cryptoService = inject(CryptoService);

  // --- State ---
  isActive = signal(false);
  portfolio = signal<{ [key: string]: number }>({ 'usd': 10000 });
  tradeLog = signal<SimOrder[]>([]);
  private intervalId: any;

  // --- Configuration ---
  simulationSpeed = signal(1000); // ms between trades
  maxTradeUsd = signal(500); // max USD value of a single trade

  // --- AI Suggestions ---
  isSuggesting = signal(false);
  suggestedSettings = signal<SuggestedSettings | null>(null);

  allCoins = this.cryptoService.cryptoData;

  constructor() {
  }

  ngOnDestroy(): void {
    this.stop();
  }

  start() {
    if (this.isActive()) return;
    this.isActive.set(true);
    this.intervalId = setInterval(() => this.runSimulationTick(), this.simulationSpeed());
  }

  stop() {
    this.isActive.set(false);
    if (this.intervalId) {
      clearInterval(this.intervalId);
      this.intervalId = null;
    }
  }

  onSpeedChange() {
    if (this.isActive()) {
      this.stop();
      this.start();
    }
  }

  private runSimulationTick() {
    const coins = this.allCoins();
    if (coins.length === 0) return;

    // 1. Pick a random coin
    const coin = coins[Math.floor(Math.random() * coins.length)];
    const coinSymbol = coin.symbol.toLowerCase();

    // 2. Decide to buy or sell (simple 50/50 logic)
    const tradeType: TradeType = Math.random() > 0.5 ? 'BUY' : 'SELL';

    const usdBalance = this.portfolio()['usd'] || 0;
    const assetBalance = this.portfolio()[coinSymbol] || 0;

    if (tradeType === 'BUY') {
      if (usdBalance < 10) return; // Not enough money to make a meaningful trade
      const tradeValue = Math.random() * Math.min(this.maxTradeUsd(), usdBalance);
      if (tradeValue < 1) return; // Too small

      const amount = tradeValue / coin.current_price;
      this.executeTrade(coin, amount, 'BUY');

    } else { // SELL
      if (assetBalance <= 0) return; // Nothing to sell
      const amountToSell = Math.random() * assetBalance;
       if (amountToSell * coin.current_price < 1) return; // Too small

      this.executeTrade(coin, amountToSell, 'SELL');
    }
  }

  private executeTrade(coin: Cryptocurrency, amount: number, type: TradeType) {
      const coinSymbol = coin.symbol.toLowerCase();
      const price = coin.current_price;
      const cost = amount * price;

      this.portfolio.update(p => {
          const newPortfolio = {...p};
          if (type === 'BUY') {
              newPortfolio['usd'] -= cost;
              newPortfolio[coinSymbol] = (newPortfolio[coinSymbol] || 0) + amount;
          } else { // SELL
              newPortfolio['usd'] += cost;
              newPortfolio[coinSymbol] -= amount;
          }
          return newPortfolio;
      });

      const logEntry: SimOrder = { id: Date.now(), coin, type, amount, price, cost };
      this.tradeLog.update(log => [logEntry, ...log].slice(0, 100));
  }

  async getAiSuggestedSettings() {
    this.isSuggesting.set(true);
    this.suggestedSettings.set(null);
    try {
        const ai = new GoogleGenAI({ apiKey: (globalThis as any).process.env.API_KEY as string });
        const marketData = this.allCoins().map(c => 
            `- ${c.name}: Price=${this.formatCurrency(c.current_price)}, 24h Change=${c.price_change_percentage_24h.toFixed(2)}%`
        ).join('\n');

        const prompt = `
            You are a trading bot strategist. Based on the following crypto market data, suggest optimal settings for a trading simulator.
            The available settings are 'simulationSpeed' (time in ms between trades, 500-3000) and 'maxTradeUsd' (max USD value per trade, 50-2000).
            - A lower speed (e.g., 500ms) is aggressive. A higher speed (e.g., 2500ms) is conservative.
            - A higher max trade size is riskier.

            Current Market Data:
            ${marketData}

            Analyze the overall market sentiment (e.g., volatile, bullish, bearish, stable) from the data and provide settings that fit that sentiment.
            Return your response in the specified JSON format.
        `;

        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        strategyName: { type: Type.STRING, description: 'A creative name for the trading strategy.' },
                        rationale: { type: Type.STRING, description: 'A brief explanation for the chosen settings based on market data.' },
                        simulationSpeed: { type: Type.INTEGER, description: 'The suggested speed in milliseconds.' },
                        maxTradeUsd: { type: Type.INTEGER, description: 'The suggested max trade size in USD.' },
                    },
                    required: ["strategyName", "rationale", "simulationSpeed", "maxTradeUsd"]
                },
            },
        });

        const resultText = response.text.trim();
        this.suggestedSettings.set(JSON.parse(resultText));

    } catch (error) {
        console.error("AI Suggestion failed:", error);
        alert("Failed to get AI-suggested settings. Please check the console.");
    } finally {
        this.isSuggesting.set(false);
    }
  }

  applySuggestedSettings() {
    const settings = this.suggestedSettings();
    if (settings) {
      this.simulationSpeed.set(settings.simulationSpeed);
      this.maxTradeUsd.set(settings.maxTradeUsd);
      this.suggestedSettings.set(null); // Hide after applying
    }
  }

  totalPortfolioValueUSD = computed(() => {
    const currentPortfolio = this.portfolio();
    const currentPrices = new Map(this.allCoins().map(c => [c.symbol.toLowerCase(), c.current_price]));
    let totalValue = currentPortfolio['usd'] || 0;
    for (const symbol in currentPortfolio) {
      if (symbol !== 'usd') {
        const amount = currentPortfolio[symbol];
        const price = currentPrices.get(symbol);
        if (amount > 0 && typeof price === 'number') {
          totalValue += amount * price;
        }
      }
    }
    return totalValue;
  });

  formatCurrency(value: number): string {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(value);
  }

  formatNumber(value: number | undefined): string {
      if (value === undefined) return '0.0000';
      return value.toFixed(4);
  }
}

